using System.Text.Json;
using System.Text.Json.Serialization.Metadata;

// Options with the default reflection-based resolver
var options = new JsonSerializerOptions(JsonSerializerDefaults.Web);

// 1. GetTypeInfo<T>() — returns JsonTypeInfo<T> directly (no cast needed)
JsonTypeInfo<Person> personInfo = options.GetTypeInfo<Person>();
Console.WriteLine($"GetTypeInfo<Person> => Type: {personInfo.Type.Name}");

string json = JsonSerializer.Serialize(new Person("Alice", 30), personInfo);
Console.WriteLine($"Serialized: {json}");

// 2. TryGetTypeInfo<T>() — probe without throwing
if (options.TryGetTypeInfo<Person>(out JsonTypeInfo<Person>? found))
{
    Console.WriteLine($"TryGetTypeInfo<Person> succeeded => {found!.Type.Name}");
}

// Now demonstrate a case where metadata is NOT available.
// Use a source-gen context that only knows about Person.
var restricted = new JsonSerializerOptions { TypeInfoResolver = SmallContext.Default };

if (restricted.TryGetTypeInfo<int>(out JsonTypeInfo<int>? intInfo))
{
    Console.WriteLine($"TryGetTypeInfo<int> succeeded => {intInfo!.Type.Name}");
}
else
{
    Console.WriteLine("TryGetTypeInfo<int> returned false — no metadata available");
}

// Types -------------------------------------------------------------------
public record Person(string Name, int Age);

[JsonSourceGenerationOptions(WriteIndented = false)]
[JsonSerializable(typeof(Person))]
public partial class SmallContext : JsonSerializerContext;

